INSERT INTO text_library (id, title, category, exam_type, difficulty, word_count, estimated_read_time, body, tags, status)
VALUES
  (gen_random_uuid(), 'Hücrenin Yapısı ve Organelleri', 'Fen Bilimleri', 'LGS', 2, 320, 3,
E'Hücre, tüm canlıların yapı ve işlev birimidir. Gözle görülemeyen bu küçük yapılar, yaşamın temel taşlarını oluştururlar. Bilim insanları hücreleri ilk kez mikroskobun icadından sonra keşfetmiş ve zamanla hücre teorisini geliştirmişlerdir. Bu teoriye göre tüm canlılar hücrelerden oluşmakta, yeni hücreler mevcut hücrelerden meydana gelmekte ve yaşamsal faaliyetler hücrede gerçekleşmektedir.\n\nHücrenin dışını çevreleyen hücre zarı, maddelerin hücreye girip çıkmasını düzenler. Seçici geçirgen özelliği sayesinde faydalı maddeleri içeri alırken zararlı atıkları dışarı iter. Hücre zarının içinde sitoplazma bulunur; bu jel benzeri sıvı ortamda organeller yüzerler.\n\nÇekirdek, hücrenin kontrol merkezidir. DNA moleküllerini barındıran çekirdek, hücrenin büyümesini, bölünmesini ve işlevlerini yönetir. Mitokondri ise hücrenin enerji santralidir; besinlerden elde edilen enerjiyi ATP molekülüne dönüştürür. Kloroplastlar bitkiye özgü organellerdir ve fotosentez yaparak güneş enerjisini kimyasal enerjiye çevirirler. Ribozomlar protein sentezinin gerçekleştiği küçük yapılardır; hücrenin her yanında bulunabilirler.',
  ARRAY['hücre','organel','biyoloji','LGS'], 'published'),

  (gen_random_uuid(), 'Türkiye''nin Coğrafi Bölgeleri', 'Sosyal Bilgiler', 'LGS', 2, 290, 3,
E'Türkiye, yedi coğrafi bölgeye ayrılmaktadır: Karadeniz, Marmara, Ege, Akdeniz, İç Anadolu, Doğu Anadolu ve Güneydoğu Anadolu. Bu bölgeler iklim, bitki örtüsü, nüfus yoğunluğu ve ekonomik faaliyetler bakımından birbirinden belirgin biçimde farklılaşır.\n\nEge ve Akdeniz bölgeleri Akdeniz iklimine sahip olup kışları ılıman ve yağışlı, yazları sıcak ve kurudur. Bu iklim zeytinyağı, narenciye ve üzüm üretimine elverişlidir. Karadeniz bölgesi ise her mevsim yağışlı bir iklime sahiptir; fındık, çay ve mısır bu bölgenin başlıca tarım ürünleridir.\n\nİç Anadolu, step ikliminin hâkim olduğu geniş bir platodur. Tahıl tarımı ve hayvancılık burada yaygındır. Doğu Anadolu bölgesi karasal iklimin en sert yaşandığı yerdir; kışlar çok soğuk ve karlı geçer. Güneydoğu Anadolu ise sıcak ve kurak yapısıyla pamuk ve antep fıstığı tarımına uygundur. Marmara bölgesi sanayinin ve nüfusun en yoğun olduğu bölgedir; İstanbul bu bölgenin merkezi konumundadır.',
  ARRAY['coğrafya','bölgeler','Türkiye','LGS'], 'published'),

  (gen_random_uuid(), 'Işığın Kırılması ve Optik Olaylar', 'Fen Bilimleri', 'LGS', 3, 305, 3,
E'Işık, bir ortamdan diğerine geçerken yön değiştirirse buna kırılma denir. Örneğin havadan suya geçen bir ışık demeti, iki ortam arasındaki sınırda kırılarak ilerler. Bu olayın temelinde ışığın farklı ortamlardaki hızları arasındaki fark yatmaktadır; ışık yoğun ortamlarda daha yavaş hareket eder.\n\nKırılma açısı ve gelme açısı arasındaki ilişki Snell yasasıyla ifade edilir. Buna göre ışık ışının yoğun ortamdan seyrek ortama geçerken normale göre uzaklaştığı, seyrek ortamdan yoğun ortama geçerken ise normale yaklaştığı görülür. Gökkuşağı, yağmur damlalarının güneş ışığını kırmasıyla oluşan güzel bir doğa olayıdır.\n\nYansıma ise ışığın bir yüzeyle karşılaşınca geri dönmesi olayıdır. Düzgün yüzeylerde düzenli yansıma, pürüzlü yüzeylerde ise dağınık yansıma gözlemlenir. Aynalar düzgün yansımanın en yaygın örneğidir. Çukur ve tümsek aynalar ise ışık demetlerini odaklayarak ya da yayarak büyütme veya küçültme etkileri oluştururlar; bu özellikten teleskopta, farklarda ve güneş kolektörlerinde yararlanılır.',
  ARRAY['optik','ışık','fizik','LGS'], 'published'),

  (gen_random_uuid(), 'Osmanlı''nın Yükseliş Dönemi', 'Tarih', 'LGS', 2, 280, 3,
E'Osmanlı Devleti, 1299 yılında Osman Bey tarafından kurulan küçük bir beylikten zamanla dünyanın en güçlü imparatorluklarından birine dönüşmüştür. Yükseliş döneminin en önemli hükümdarı hiç kuşkusuz Fatih Sultan Mehmet''tir. Onun 1453''te İstanbul''u fethiyle Ortaçağ kapanmış ve Yeniçağ başlamıştır.\n\nYavuz Sultan Selim döneminde Osmanlı, Mısır''ı ve Hicaz''ı topraklarına katarak hilafetin sahibi oldu. Bu gelişme Osmanlı''ya İslam dünyasının lideri konumunu kazandırdı. Kanuni Sultan Süleyman ise hem siyasi hem de hukuki alanda yaptığı düzenlemelerle adını tarihe altın harflerle yazdırmıştır. "Kanuni" unvanı da bu dönemin yarattığı hukuki düzenin bir simgesidir.\n\nYükseliş döneminde devşirme sistemi Osmanlı ordusunu güçlendirmiş; yeniçeri ocakları savaş meydanlarında üstün başarılar elde etmiştir. Toprak kullanım sistemleri olan tımar ve dirlik düzenlemeleri devletin ekonomisini canlı tutarken çeşitli etnik ve dini toplulukların millet sistemiyle bir arada yaşamasına olanak tanınmıştır.',
  ARRAY['osmanlı','tarih','LGS'], 'published'),

  (gen_random_uuid(), 'Türkçede Sözcük Türleri', 'Türkçe', 'LGS', 1, 260, 2,
E'Türkçede sözcükler anlamlarına ve cümlede üstlendikleri işlevlere göre sekiz temel türe ayrılır: isim, sıfat, zamir, zarf, fiil, edat, bağlaç ve ünlem. Bu sınıflandırma dilin düzenli ve anlaşılır kullanılmasının temelini oluşturur.\n\nİsimler varlıkları ve kavramları karşılayan sözcüklerdir; "taş, sevgi, okul, hava" gibi. Sıfatlar isimleri niteleyen ya da belirten sözcüklerdir: "güzel çiçek, üç kitap, bu ev". Zamirler isimlerin yerini tutarlar: "ben, sen, o, biz, onlar". Zarflar ise fiilleri, sıfatları ve diğer zarfları nitelerler: "hızlı koştu, çok güzel".\n\nFiiller eylemleri, hareketleri ve durumları bildiren sözcüklerdir; Türkçede fiil çekimi son derece zengindir. Edatlar tek başlarına anlam taşımayan ama cümlede anlam ilişkisi kuran sözcüklerdir: "için, ile, gibi, kadar". Bağlaçlar sözcükleri ya da cümleleri birbirine bağlarlar: "ve, ama, fakat, ya da". Ünlemler duyguları ve seslenimleri ifade ederler: "ah, of, hey, bravo". Bu sözcük türlerini iyi kavramak, hem yazma hem de okuma becerilerini güçlendirir.',
  ARRAY['gramer','sözcük türleri','Türkçe','LGS'], 'published'),

  (gen_random_uuid(), 'Besinlerin Sindirimi ve Emilimi', 'Fen Bilimleri', 'LGS', 2, 310, 3,
E'Sindirim sistemi, vücuda alınan besinleri parçalayarak hücrelerin kullanabileceği küçük moleküllere dönüştüren karmaşık bir organlardır bütünüdür. Sindirim ağızdan başlar; dişler besinleri fiziksel olarak parçalarken tükürük içindeki enzimler nişastayı kimyasal olarak sindirmeye başlar.\n\nYemek borusundan geçen besinler mideye ulaşır. Midede mide özsuyu, özellikle proteinleri parçalayan enzimler içerir. Kuvvetli asit ortamı zararlı bakterileri de yok eder. Mideden çıkan yarı sindirilmiş besinler ince bağırsağa geçer. İnce bağırsak sindirim ve emilimin büyük çoğunluğunun gerçekleştiği yerdir.\n\nKaraciğer salgıladığı safra ile yağları parçalamada yardımcı olurken pankreas enzim salgılayarak protein, yağ ve karbonhidrat sindirimini tamamlar. İnce bağırsağın iç yüzeyindeki parmak benzeri çıkıntılara villüs denir; bu yapılar emilim yüzeyini büyük ölçüde artırır. Sindirilmiş besinler buradan kana karışarak tüm vücuda taşınır. Sindirilemeyen atıklar kalın bağırsağa geçer ve su emilimi sonrası dışarı atılır.',
  ARRAY['sindirim','biyoloji','LGS'], 'published'),

  (gen_random_uuid(), 'Elektrik ve Manyetizma', 'Fen Bilimleri', 'LGS', 3, 295, 3,
E'Elektrik, yüklü parçacıkların hareketiyle ortaya çıkan bir enerji biçimidir. Atomun çekirdeği çevresinde dönen elektronlar negatif yüklüdür; bu elektronların bir iletken üzerinden akması elektrik akımını oluşturur. Elektrik akımının birimi amperdir ve bu akımı üreten gerilim farkının birimi ise volttur.\n\nManyetizma ise mıknatısların ve elektrik akımının çevresinde oluşan kuvvet alanlarıyla ilgilidir. Her mıknatısın kuzey ve güney olmak üzere iki kutbu bulunur; aynı kutuplar birbirini iterken zıt kutuplar birbirini çeker. Dünya''nın da kendi manyetik alanı vardır ve pusulalar bu alan sayesinde çalışır.\n\nElektromanyetizma, elektrik ve manyetizmanın birbirini etkilediği ve birbirine dönüşebildiği kapsamlı bir konu alanıdır. Bir elektrik akımının çevresinde manyetik alan oluşması bu ilişkinin temelini oluşturur. Değişen bir manyetik alanın ise elektrik akımı üretebilmesi elektrik jeneratörlerinin çalışma prensibini oluşturur. Günümüzde kullandığımız elektrik motorları, jeneratörler ve transformatörler bu prensibe dayanmaktadır.',
  ARRAY['elektrik','manyetizma','fizik','LGS'], 'published'),

  (gen_random_uuid(), 'Ekosistem ve Biyoçeşitlilik', 'Fen Bilimleri', 'LGS', 2, 280, 3,
E'Ekosistem, bir bölgede yaşayan tüm canlı organizmaların birbirleriyle ve cansız çevreleriyle oluşturdukları karmaşık sistemi tanımlar. Ormanlar, mercan resifleri, çöller ve sulak alanlar birer ekosisteme örnektir. Her ekosistemin kendine özgü iklim koşulları, bitki örtüsü ve hayvan toplulukları bulunur.\n\nEkosistemlerin sağlıklı işleyişi için biyoçeşitlilik kritik öneme sahiptir. Biyoçeşitlilik, bir bölgede yaşayan tür sayısı ve bu türlerin genetik farklılığıdır. Yüksek biyoçeşitlilik ekosistemlere esneklik kazandırır; hastalık veya doğal afet durumunda sistem kendini daha kolay onarabilir.\n\nBeslenme ilişkileri ekosistemde enerji akışını sağlar. Üreticiler (bitkiler) güneş enerjisini kimyasal enerjiye dönüştürürler. Birincil tüketiciler bitkilerle beslenen otçul hayvanlardır. İkincil tüketiciler ise otçullarla beslenen etçillerdir. Ayrıştırıcılar ölü organik maddeleri minerallere dönüştürerek besinlerin döngüsünü tamamlar. İnsan faaliyetleri bu hassas dengeyi bozabilmekte; ormansızlaşma ve kirlilik pek çok türü yok oluşun eşiğine getirmektedir.',
  ARRAY['ekosistem','biyoçeşitlilik','çevre','LGS'], 'published'),

  (gen_random_uuid(), 'Anadolu Medeniyetleri', 'Tarih', 'LGS', 2, 270, 3,
E'Anadolu, binlerce yıl boyunca pek çok büyük uygarlığa ev sahipliği yapmıştır. Tarih öncesi dönemden günümüze uzanan bu köklü geçmiş, Anadolu''yu "Medeniyetlerin Beşiği" olarak adlandırmamızı sağlar.\n\nM.Ö. 2000''li yıllarda Hitit İmparatorluğu Orta Anadolu''da kurulmuştur. Hititler demir işleme tekniklerini geliştirmiş ve kendi yazı sistemlerini oluşturmuşlardır. Dünyanın bilinen ilk barış antlaşması olan Kadeş Antlaşması Hititler ile Mısır arasında imzalanmıştır. Hititlerin yıkılmasının ardından Frigya, Lidya ve Urartu krallıkları Anadolu''da hâkimiyet kurmuşlardır.\n\nM.Ö. 334''te Büyük İskender Anadolu''yu fethetti ve Hellenistik dönem başladı. Roma hâkimiyeti döneminde Efes, Bergama ve Antakya gibi şehirler Akdeniz dünyasının önemli merkezleri hâline geldi. Bizans döneminde Anadolu Hristiyanlığın kalbi oldu. 1071 Malazgirt zaferinin ardından Türk boylarının Anadolu''ya yerleşmesiyle birlikte Türk-İslam medeniyetinin temelleri atıldı.',
  ARRAY['tarih','Anadolu','medeniyet','LGS'], 'published'),

  (gen_random_uuid(), 'Demokrasi ve Temel Haklar', 'Vatandaşlık', 'LGS', 2, 265, 3,
E'Demokrasi, halkın kendi kendini yönettiği ya da seçtiği temsilciler aracılığıyla yönetildiği bir sistem olarak tanımlanabilir. Antik Yunan''ın Atina şehrinde M.Ö. 5. yüzyılda ilk örnekleri görülen demokrasi, günümüzde dünyanın pek çok ülkesinde benimsenmiştir.\n\nTemsili demokrasilerde vatandaşlar belirli aralıklarla yapılan seçimlerle temsilcilerini belirler. Yasamayı (yasa yapmayı), yürütmeyi (yasaları uygulamayı) ve yargıyı (adaleti dağıtmayı) birbirinden bağımsız kurumların üstlenmesi "kuvvetler ayrılığı" ilkesini oluşturur. Bu ilke, iktidarın tek elde toplanmasını önler.\n\nDemokrasinin vazgeçilmez koşulu temel hak ve özgürlüklerin güvence altına alınmasıdır. İfade özgürlüğü, basın özgürlüğü, toplanma hakkı ve adil yargılanma hakkı bu temel güvenceler arasında sayılabilir. Türkiye Cumhuriyeti Anayasası bu hakları güvence altına almış olup her vatandaş bu haklardan eşit biçimde yararlanma hakkına sahiptir.',
  ARRAY['demokrasi','vatandaşlık','hukuk','LGS'], 'published');

