INSERT INTO text_library (id, title, category, exam_type, difficulty, word_count, estimated_read_time, body, tags, status)
VALUES
  (gen_random_uuid(), 'Evrenin Yapısı ve Kozmoloji', 'Fizik', 'TYT', 3, 330, 4,
E'Evren, yaklaşık 13,8 milyar yıl önce gerçekleşen Büyük Patlama ile başladığı düşünülen muazzam bir varlık alanıdır. Bu patlamanın ardından son derece yoğun ve sıcak olan madde hızla genişlemiş ve soğuyarak bugünkü yapısını oluşturmuştur. Modern kozmoloji, bu sürecin matematiksel modellerini geliştirerek evrenin kökenini ve evrimini anlamamızı sağlamaktadır.\n\nEvrende yaklaşık iki trilyon galaksi bulunmaktadır. Galaksiler, milyarlarca yıldız ve bunları bir arada tutan karanlık maddeden oluşmuş devasa sistemlerdir. Samanyolu galaksimiz yaklaşık 200-400 milyar yıldız barındırır ve Güneş sistemi bu galaksinin kenarlarından birinde yer alır. Galaksiler küme ve süper küme adı verilen daha büyük yapılar oluşturmaktadır.\n\nÇağdaş astronominin en büyük gizemlerinden biri karanlık madde ve karanlık enerjidir. Gözlemlenebilir madde evrenin yalnızca yüzde beşini oluşturmaktadır; geri kalanı bilinmeyen karanlık madde ve karanlık enerjiden ibarettir. Karanlık enerji evrenin genişlemesini hızlandırmakta olup bu hız giderek artmaktadır. Evrenin geleceği; Büyük Çöküş, Büyük Dondurma ya da Büyük Yırtılma gibi farklı senaryolarla tartışılmaktadır.',
  ARRAY['evren','kozmoloji','fizik','TYT'], 'published'),

  (gen_random_uuid(), 'DNA''nın Keşfi ve Genetik Devrim', 'Biyoloji', 'TYT', 3, 340, 4,
E'1953 yılında James Watson ve Francis Crick''in DNA''nın çift sarmal yapısını keşfetmesi, biyoloji tarihinin dönüm noktalarından birini oluşturmuştur. Bu keşif; Rosa Franklin''in X-ışını kırınım görüntüleri gibi önceki çalışmaların üzerine inşa edilmiştir ve genetik bilimini büyük ölçüde ilerletti.\n\nDNA (deoksiribonükleik asit) dört nükleotid bazı içerir: adenin, timin, guanin ve sitozin. Bu bazların dizilişi genetik şifreyi oluşturur. Gen ise belirli bir proteini kodlayan DNA dizisidir. Ribozomlar bu bilgiyi okuyarak aminoasitleri bir araya getirir ve proteini sentezler. Proteinler vücudun yapı taşları ve biyokimyasal süreçlerin yöneticileri olduğundan bu süreç hayatın sürdürülmesi açısından kritiktir.\n\nGenetik devrimin pratik yansımaları son derece geniştir. Gen mühendisliği yöntemiyle insülin üreten bakteri hücreleri elde edilebilmektedir. CRISPR-Cas9 teknolojisi DNA''nın istenilen noktasında değişiklik yapmaya olanak tanımaktadır. Kanser tedavisinde tümörün genetik profilini analiz eden kişiselleştirilmiş tıp yaklaşımları geliştirmektedir. Adli tıpta DNA parmak izi suçluların tespitinde belirleyici rol oynamaktadır.',
  ARRAY['DNA','genetik','biyoloji','TYT'], 'published'),

  (gen_random_uuid(), 'Termodinamiğin Yasaları', 'Fizik', 'TYT', 4, 315, 4,
E'Termodinamik, ısı ve iş arasındaki ilişkileri inceleyen fizik dalıdır. Birinci Yasa enerjinin korunumunu ifade eder: enerji yoktan var edilemez veya yok edilemez, yalnızca bir biçimden diğerine dönüştürülebilir. Bu yasa, bir ısı makinesinin yaptığı işin ve ortama verdiği ısının toplamının aldığı ısıya eşit olduğunu söyler.\n\nİkinci Yasa ise doğal süreçlerin yönünü belirler. Entropi —bir sistemin düzensizlik ölçüsü— izole bir sistemde her zaman artar ya da en kötü ihtimalle sabit kalır. Bu yasa, ısının soğuktan sıcağa kendiliğinden akmadığını ve mükemmel verimli bir makinenin gerçekleştirilemeyeceğini ortaya koyar. Entropi kavramı evrenin genel bir düzensizliğe doğru aktığını da öngörür.\n\nÜçüncü Yasa ise mutlak sıfır sıcaklığına (−273,15 °C) ulaşılmasının mümkün olmadığını ifade eder. Mutlak sıfırda atomik hareketin durması beklenir, ancak kuantum mekaniği sıfır nokta enerjisinin her zaman var olduğunu gösterir. Bu yasalar buhar makinelerinden buzdolabına, güç santrallerinden uzay araçlarına pek çok teknolojik sistemin tasarımında temel alınmaktadır.',
  ARRAY['termodinamik','fizik','enerji','TYT'], 'published'),

  (gen_random_uuid(), 'Organik Kimya Temelleri', 'Kimya', 'TYT', 4, 325, 4,
E'Organik kimya, karbon bileşiklerini inceleyen kimya dalıdır. Karbonun dört elektron bağı kurabilme özelliği, zincirleme ve halkalı yapıda milyonlarca farklı bileşiğin oluşmasına olanak tanır. Yaşayan organizmaların temel yapı taşları olan proteinler, karbonhidratlar, yağlar ve nükleik asitler birer organik bileşiktir.\n\nAlkanlar, sadece tekli C-C ve C-H bağları içeren doymuş hidrokarbonlardır. Metan, etan, propan ve bütan bilinen alkanlara örnektir. Alkenler ise en az bir çift bağ içerirken alkinler üçlü bağ barındırır. Aromatik bileşikler benzenden türeyen özel halkalı yapılardır ve kararlılıklarıyla dikkat çekerler.\n\nFonksiyonel gruplar, organik bileşiklerin kimyasal özelliklerini büyük ölçüde belirler. Alkol grubu (-OH) suyla karışabilirliği artırırken karboksil grubu (-COOH) asilik kazandırır. Amin grubu (-NH2) bazik özelliklere yol açar. Polimerizasyon sayesinde basit monomer birimler birleşerek lastik, plastik ve sentetik elyaf gibi günlük hayatta yaygın kullanılan malzemeleri oluşturur.',
  ARRAY['organik kimya','karbon','TYT'], 'published'),

  (gen_random_uuid(), 'Sinir Sistemi ve Nöronlar', 'Biyoloji', 'TYT', 3, 300, 3,
E'Sinir sistemi, vücuttaki tüm faaliyetleri koordine eden ve çevreyle iletişimi sağlayan karmaşık bir ağdır. İki temel bölümden oluşur: Merkezi Sinir Sistemi (beyin ve omurilik) ve Periferik Sinir Sistemi (vücuda yayılan sinir ağı). Bu iki sistem birlikte çalışarak yaşamsal işlevleri düzenler.\n\nNöron, sinir sisteminin temel yapı ve işlev birimidir. Her nöron; hücre gövdesi, akson ve dendritlerden oluşur. Dendritler diğer nöronlardan gelen sinyalleri alırken akson bu sinyali ileriye taşır. Nöronlar arasındaki bağlantı noktalarına sinaps denir; sinyaller burada nörotransmitter adı verilen kimyasal maddeler aracılığıyla iletilir.\n\nBeyin yaklaşık 86 milyar nörondan oluşmakta ve sürekli aktif olmaktadır. Serebral korteks düşünme, konuşma ve planlama gibi yüksek düzey işlevleri yönetirken serebellum denge ve motor koordinasyonu sağlar. Beyin sapı ise uyku, solunum ve kalp atışı gibi otomatik işlevleri kontrol eder. Nörobilimdeki son gelişmeler, beynin stres veya öğrenme gibi deneyimler sonucu yapısal olarak yeniden şekillenebildiğini (nöroplastisite) ortaya koymuştur.',
  ARRAY['sinir sistemi','nöron','biyoloji','TYT'], 'published'),

  (gen_random_uuid(), 'Cumhuriyet Dönemi Türk Şiiri', 'Edebiyat', 'TYT', 3, 310, 3,
E'Cumhuriyet''in ilanıyla birlikte Türk şiiri de köklü bir dönüşüm sürecine girmiştir. Milli mücadele yıllarının coşkusunu yansıtan şiirler yerini zamanla toplumsal sorunları ele alan, bireyin iç dünyasını derinlemesine araştıran eserlere bırakmıştır.\n\nNazım Hikmet, serbest ölçü ve siyasi içerikli şiirleriyle Türk şiirini yeniden biçimlendirmiştir. "İnsan Manzaraları" adlı uzun manzumesi, Anadolu insanını belgesel bir gerçekçilikle işler. Onun şiiri yalnızca biçimsel yenilikler açısından değil, toplumsal meseleleri cesurca dile getirmesi bakımından da çığır açıcıdır.\n\nOrhan Veli, Melih Cevdet Anday ve Oktay Rifat''ın öncülük ettiği Garip akımı, 1941''de kaleme alınan bir manifesto ile başlamıştır. Bu akım şiirden musikili ve süslü dili dışlayarak gündelik konuşma diline ve sıradan insanların yaşamına yönelmiştir. Sonraki dönemde İkinci Yeni hareketi ise anlam belirsizliğini ve bilinçdışını ön plana çıkarmıştır. Cemal Süreya ve Turgut Uyar bu dönemin öncü isimleridir.',
  ARRAY['şiir','edebiyat','Cumhuriyet','TYT'], 'published'),

  (gen_random_uuid(), 'Kimyasal Tepkimeler ve Denge', 'Kimya', 'TYT', 3, 295, 3,
E'Kimyasal tepkimeler, bir ya da birden fazla maddenin farklı özelliklere sahip yeni maddeler oluşturmak üzere dönüştüğü süreçlerdir. Tepkimeler ekzotermik (ısı açığa çıkaran) ya da endotermik (ısı soğuran) olabilir. Yanma, korozyon ve fotosentez doğada karşılaştığımız kimyasal tepkimelere örnektir.\n\nTepkime hızı birim zamanda tüketilen reaktant ya da oluşan ürün miktarıyla ifade edilir. Sıcaklık, konsantrasyon, yüzey alanı ve katalizörler tepkime hızını etkileyen başlıca faktörlerdir. Katalizörler, kendileri tükenmeksizin tepkime için gerekli olan aktivasyon enerjisini düşürerek hızı artıran maddelerdir.\n\nKimyasal denge, geri dönüşümlü bir tepkimede ileri ve geri tepkimelerin hızlarının eşitlendiği durumdur. Le Chatelier ilkesine göre bir denge sistemine dışarıdan baskı uygulandığında sistem bu baskıyı dengeleyecek yönde kayar. Örneğin konsantrasyon artırıldığında sistem ürün oluşumunu hızlandırır; sıcaklık değiştirildiğinde ise ısıl denge değişir. Bu ilkeler kimya sanayiinde ürün verimini optimize etmek için yaygın olarak kullanılır.',
  ARRAY['kimya','tepkime','denge','TYT'], 'published'),

  (gen_random_uuid(), 'Atom Modelleri ve Kuantum Teorisi', 'Kimya', 'TYT', 4, 320, 4,
E'Atomun yapısını anlamaya yönelik tarihsel süreç, her yeni gözlemle birlikte modellerin evrilmesini beraberinde getirmiştir. John Dalton''ın 19. yüzyılda önerdiği model atomu bölünemez katı bir küre olarak tasavvur etti. Thomson''ın elektron keşfinin ardından "üzümlü kek" modeli ortaya çıktı; buna göre negatif yüklü elektronlar pozitif yüklü bir madde içine gömülüydü.\n\nRutherford''ın altın levha deneyi (1911), atomun büyük bölümünün boş uzaydan ibaret olduğunu ve pozitif yükün çekirdek adı verilen küçük bir bölgede yoğunlaştığını ortaya koydu. Bohr ise buna elektronların belirli enerji düzeylerinde (yörüngelerde) döndüğünü ekledi ve hidrojen atomunun spektrumunu başarıyla açıkladı.\n\nModern kuantum mekaniği, elektronların kesin konumlarının belirsizlik ilkesi nedeniyle saptanamayacağını ortaya koymuştur. Bunun yerine elektronların uzayda belirli bölgelerde bulunma olasılığını gösteren orbital kavramı kullanılmaktadır. Schrödinger denkleminin çözümleri olan dalga fonksiyonları bu olasılık dağılımlarını matematiksel olarak ifade eder. Bu anlayış atom spektroskopisi, kimyasal bağlar ve maddenin genel özelliklerini açıklamada temel kaynak olmaktadır.',
  ARRAY['atom','kuantum','kimya','TYT'], 'published'),

  (gen_random_uuid(), 'Dalga Hareketi ve Ses Fiziği', 'Fizik', 'TYT', 3, 285, 3,
E'Dalgalar enerjiyi maddeden maddeye aktaran salınım hareketleridir. Mekanik dalgalar yayılmak için bir ortam gerektirirken elektromanyetik dalgalar (ışık, radyo vb.) boşlukta da yayılabilir. Ses dalgaları mekanik dalgalara örnektir; bu nedenle uzayın sessizliğinde ses işitilemez.\n\nSesin hızı ortama göre değişir. Havada yaklaşık 343 m/s olan ses hızı, sıvılarda ve katılarda çok daha yüksektir. Sıcaklık arttıkça hava molekülleri daha hızlı hareket edeceğinden sesin hızı da artar. Frekansı insan kulağının duyamayacağı kadar yüksek olan ultrasonik dalgalar tıbbi görüntülemede ve sonar teknolojisinde yaygın biçimde kullanılır.\n\nDoppler etkisi, ses veya ışık kaynağı ile gözlemci arasındaki görece hareketin frekansı değiştirdiği ilginç bir olgudur. Yaklaşan bir arabanın sireni daha tiz (yüksek frekans), uzaklaşan arabanın sireni ise daha pes (düşük frekans) duyulur. Astronomlar bu etkiyi galaksilerin uzaklaşma hızlarını ölçmekte ve evrenin genişlediğini doğrulamakta kullanmaktadırlar.',
  ARRAY['dalga','ses','fizik','TYT'], 'published'),

  (gen_random_uuid(), 'Tanzimat Edebiyatı ve Yenilik', 'Edebiyat', 'TYT', 3, 290, 3,
E'Tanzimat Dönemi (1839-1876), Osmanlı toplumunda Batı tarzı modernleşmenin edebiyata yansıdığı önemli bir dönemdir. Bu dönemde roman, hikâye, tiyatro ve gazete gibi Batılı türler Türk edebiyatıyla buluşmuş; toplumsal sorunlar sanatsal ifadenin merkezine yerleşmiştir.\n\nBirinci kuşak Tanzimat yazarları arasında Şinasi, Namık Kemal ve Ziya Paşa öne çıkar. Namık Kemal vatanseverlik, özgürlük ve vatan sevgisini eserlerinde işleyerek toplumsal bilinci uyandırmayı hedeflemiştir. "Vatan Yahut Silistre" adlı tiyatro eseri büyük yankı uyandırmıştır. Şinasi ise Türkçe gazete geleneğini kurmuş ve noktalama işaretlerini yaygınlaştırmıştır.\n\nİkinci kuşak yazarlarından Recaizade Mahmut Ekrem ve Abdülhak Hamit Tarhan ise daha bireysel ve estetik kaygıları ön plana çıkarmıştır. Samipaşazade Sezai ilk psikolojik romanlar yazmıştır. Bu dönemde "sanat toplum içindir" ile "sanat sanat içindir" tartışmaları edebiyat dünyasını derinden etkilemiş; ilerleyen yıllarda Servet-i Fünun akımına zemin hazırlamıştır.',
  ARRAY['tanzimat','edebiyat','tarih','TYT'], 'published'),

  (gen_random_uuid(), 'Enzimler ve Metabolizma', 'Biyoloji', 'TYT', 3, 300, 3,
E'Enzimler, canlı hücrelerde gerçekleşen kimyasal tepkimeleri hızlandıran biyolojik katalizörlerdir. Protein yapısındaki bu moleküller substrat adı verilen belirli moleküllere son derece seçici biçimde bağlanarak tepkime hızını milyonlarca kat artırabilirler. Bu seçicilik "anahtar-kilit" metaforuyla açıklanır: enzimin aktif bölgesi yalnızca belirli bir substrata uyum sağlar.\n\nMetabolizma, hücrede gerçekleşen tüm kimyasal tepkimelerin bütününü kapsar. Katabolik tepkimeler büyük molekülleri parçalayarak enerji açığa çıkarırken anabolik tepkimeler küçük moleküllerden büyük yapılar oluşturur. Glikoliz, sitrik asit döngüsü ve oksidatif fosforilasyon glikozdan ATP (hücresel enerji para birimi) üretiminin ardışık aşamalarıdır.\n\nEnzim aktivitesi sıcaklık, pH ve substrat konsantrasyonu gibi faktörlerden etkilenir. Her enzimin optimal çalıştığı bir sıcaklık ve pH aralığı bulunur. Aşırı sıcaklık enzimin üç boyutlu yapısını bozarak (denatürasyon) aktivitesini kaybettirir. Pek çok hastalık enzim eksikliği ya da işlevsizliğinden kaynaklanmaktadır; bu nedenle enzimler ilaç araştırmalarında önemli hedefler arasında yer almaktadır.',
  ARRAY['enzim','metabolizma','biyoloji','TYT'], 'published'),

  (gen_random_uuid(), 'Türk Edebiyatında Modernizm', 'Edebiyat', 'TYT', 3, 295, 3,
E'20. yüzyılın ortasında dünya edebiyatında yaşanan modernist akım Türk edebiyatında da derin izler bırakmıştır. Modernizm, bireysel deneyimi, bilinç akışını ve zaman anlayışındaki kırılmaları ön plana çıkarmıştır. Geleneksel anlatı yapısının yerini karmaşık iç sesler ve parçalı anlatılar almıştır.\n\nOğuz Atay ve Yusuf Atılgan Türk modernizminin önemli temsilcilerindendir. Atay''ın "Tutunamayanlar" romanı, modernist anlatı teknikleri ile Türk aydınının kimlik bunalımını birleştirdiği çığır açıcı bir eserdir. Atılgan''ın "Aylak Adam" adlı eseri ise varoluşçu izlekler taşıyan yabancılaşma temasını işler.\n\nModernist Türk edebiyatı, Batı edebiyatındaki akımları körü körüne taklit etmek yerine yerel gerçeklikle harmanlama yolunu seçmiştir. Kente göç, geleneksel değerlerin çözülmesi ve kimlik arayışı bu edebiyatın başlıca temaları olmuştur. Günümüzde ise postmodern eğilimler güçlenmiş; Orhan Pamuk ve Elif Şafak gibi yazarlar uluslararası edebiyat sahnesinde Türk sesini duyurmaktadır.',
  ARRAY['modernizm','edebiyat','roman','TYT'], 'published');

-- ══════════════════════════════════════════════════════════════
-- ALES METİNLERİ (10 adet) — Difficulty 3-5
-- ══════════════════════════════════════════════════════════════

INSERT INTO text_library (id, title, category, exam_type, difficulty, word_count, estimated_read_time, body, tags, status)
VALUES
  (gen_random_uuid(), 'Bilimsel Düşünme ve Araştırma Metodolojisi', 'Akademik', 'ALES', 4, 360, 4,
E'Bilimsel düşünme, sistematik gözleme, denetlenebilir hipotezlere ve tutarlı mantık zincirlerine dayanır. Bir fenomeni açıklamak için hipotez kurmak, ardından bu hipotezi yanlışlamaya çalışmak Karl Popper''ın yanlışlanabilirlik ölçütünün özüdür. Bilim, doğruluğu kanıtlanmış değil, henüz yanlışlanamamış önermeler bütünüdür.\n\nKolektifte araştırma metodolojisi nicel ve nitel olmak üzere iki temel paradigmayı kapsar. Nicel araştırmalar istatistiksel analiz ve ölçmeye dayanırken nitel araştırmalar katılımcı deneyimlerini yorumsamacı bir çerçevede inceler. Karma yöntem yaklaşımı ise her iki paradigmayı sentezleyerek daha kapsamlı bulgular elde etmeyi amaçlar.\n\nİç geçerlilik bir araştırmanın kendi içinde tutarlı olup olmadığını, dış geçerlilik ise sonuçların farklı bağlamlara genellenip genellenemeyeceğini sorgular. Örnekleme yöntemi, ölçüm güvenilirliği ve değişkenleri kontrol etme kapasitesi araştırmanın bilimsel değerini doğrudan belirler. Sistematik derleme ve meta-analiz ise birden fazla çalışmanın bulgularını sentezleyerek kanıt tabanını güçlendiren yöntemlerdir.',
  ARRAY['metodoloji','bilim','araştırma','ALES'], 'published'),

  (gen_random_uuid(), 'Dil Edinimi ve Evrimsel Kökenler', 'Dilbilim', 'ALES', 4, 345, 4,
E'Dil edinimi, çocukların karmaşık dilbilgisel yapıları neden explicit öğretim almaksızın hızla kavrayabildiklerini sorusunu inceleyen dilbilimin en çekici araştırma alanlarından biridir. Noam Chomsky''nin evrensel dilbilgisi hipotezi, insanların doğuştan bir dil edinim mekanizmasına sahip olduğunu öne sürer.\n\nKritik dönem hipotezine göre dil edinimi için biyolojik olarak belirlenmiş hassas bir pencere mevcuttur. Bu dönem ergenlik öncesinde kapanmakta ve sonrasında birinci dil edinimi giderek zorlaşmaktadır. Feral çocuklar üzerine yapılan çalışmalar bu hipotezi desteklemekle birlikte etik nedenlerle kontrollü deneyler yapılamamaktadır.\n\nEvrimsel dilbilim, insan dilinin nasıl ortaya çıktığını araştırır. Anatomik kanıtlar modern dil yeteneğinin yaklaşık 200.000 yıl önce Homo sapiens''te şekillendiğini düşündürmektedir. FOXP2 geni konuşma ve dil gelişiminde kritik rol oynamakta olup Neandertallerde de benzer bir versiyonunun bulunduğu saptanmıştır. Bu bulgular dilin kökenini salt biyolojik değil, kültürel-biyolojik ortak bir evrim süreci olarak ele almamızı gerektirmektedir.',
  ARRAY['dilbilim','dil','evrim','ALES'], 'published'),

  (gen_random_uuid(), 'Yapay Zeka ve Etik Sorunlar', 'Teknoloji', 'ALES', 4, 350, 4,
E'Yapay zeka sistemleri giderek artan yetenekleriyle insan karar alma süreçlerinin yerini almakta ya da bu süreçlere ortak olmaktadır. Bu dönüşüm beraberinde önemli etik soruları gündeme getirmektedir. Bir özerk sistem zarar verdiğinde sorumluluk kime aittir: yazılımcıya mı, kullanıcıya mı, yoksa üretici şirkete mi?\n\nAlgoritmik önyargı, yapay zeka sistemlerinin eğitim verilerindeki sosyal eşitsizlikleri yeniden üretmesi ya da pekiştirmesi anlamına gelir. Suç tahmin sistemleri, kredi notlandırma algoritmaları ve işe alım araçları üzerinde yapılan çalışmalar bu sistemlerin belirli demografik gruplar aleyhine orantısız biçimde çalışabildiğini göstermektedir. Önyargısız eğitim verisi oluşturmak ise kendi başına zorlu bir etik ve teknik sorundur.\n\nAçıklanabilirlik yapay zekanın en çok tartışılan konularından biridir. Derin öğrenme modelleri "kara kutu" niteliği taşıdığından kararlarını neden verdiklerini insanın anlayabileceği biçimde açıklamak güçtür. Tıbbi tanı, cezai adalet gibi yüksek riskli alanlarda açıklanabilirlik bir ön koşul olmalı mıdır? Yapay zeka yönetişimi konusunda uluslararası standartlar oluşturma çalışmaları sürmektedir.',
  ARRAY['yapay zeka','etik','teknoloji','ALES'], 'published'),

  (gen_random_uuid(), 'Ekonomik Büyüme Teorileri', 'Ekonomi', 'ALES', 4, 335, 4,
E'Ekonomik büyüme neden bazı ülkelerde sürekli ve hızlı iken diğerlerinde yavaş ya da tersine döner? Bu temel soru iktisatçıları onlarca yıldır meşgul etmektedir. Klasik büyüme modelleri sermeye ve emeği birincil üretim faktörleri olarak ele alırken Solow modeli teknolojik ilerlemenin uzun dönem büyümedeki belirleyici rolünü vurgulamıştır.\n\nİçsel büyüme teorileri, teknolojik değişimi modelin dışında değil içinde açıklama girişimidir. Paul Romer''ın öncülük ettiği bu yaklaşım, insan sermayesine ve Ar-Ge''ye yapılan yatırımların artan getiri sağladığını öne sürer. Bu bağlamda eğitim ve kurumsal kalite uzun vadeli büyümenin kritik belirleyicileri hâline gelir.\n\nKurumsal iktisat anlayışı ise mülkiyet hakları, hukuk devleti ve güvenilir piyasa kurallarının varlığının büyüme için salt fiziksel sermayeden daha belirleyici olduğunu savunur. Tarihin en hızlı kalkınma deneyimlerini yaşayan Güney Kore ve Tayvan vakaları kurumsal reformlarla ihracata dayalı sanayileşmenin bütünleşik bir strateji olarak hayata geçirildiğini göstermektedir.',
  ARRAY['ekonomi','büyüme','kalkınma','ALES'], 'published'),

  (gen_random_uuid(), 'Sosyolojide Kimlik ve Kültür', 'Sosyoloji', 'ALES', 4, 325, 4,
E'Sosyolojik açıdan kimlik, bireyin toplumsal roller, grup üyelikleri ve kültürel pratikler aracılığıyla inşa ettiği öznel ve toplumsal bir yapıdır. Kimlik ne doğuştan sabit bir öz ne de salt toplumsal koşullanmanın ürünüdür; her ikisi arasındaki dinamik gerilimde sürekli biçimlenmektedir.\n\nKültür, bir toplumun değerlerini, normlarını, sembollerini ve pratiklerini kuşaktan kuşağa aktaran yaşayan bir miras olarak tanımlanabilir. Küreselleşme süreci yerel kültürleri hem zenginleştiren hem de homojenleştiren çeşitli baskılar üretmektedir. Kültürel melezlik, farklı kültürlerin buluşmasından ortaya çıkan yeni ifade biçimlerini tanımlar.\n\nSosyal kimlik teorisi (Tajfel ve Turner) bireylerin mensubu oldukları gruptan olumlu bir öz-kavram türetmeye güdülendiğini öne sürer. Bu süreç iç grup kayırmacılığı ve dış gruba karşı önyargı eğilimlerini pekiştirebilir. Interseksiyonellik (Kimberlé Crenshaw) ise kimliğin ırk, sınıf, toplumsal cinsiyet gibi bileşenlerinin birbirinden bağımsız değil, kesişen ve birbirini güçlendiren eksenlerde anlaşılması gerektiğini vurgular.',
  ARRAY['kimlik','kültür','sosyoloji','ALES'], 'published'),

  (gen_random_uuid(), 'Felsefede Bilgi Kuramı (Epistemoloji)', 'Felsefe', 'ALES', 5, 355, 4,
E'Epistemoloji, bilginin doğası, kaynağı, kapsamı ve güvenilirliğini sorgulayan felsefe dalıdır. "Neyi bilebiliriz?" ve "Bir inancın bilgi sayılabilmesi için ne gereklidir?" soruları bu alanın merkezinde yer alır. Geleneksel tanıma göre bilgi "doğrulanmış doğru inanç" olarak tanımlanmıştır; ancak Edmund Gettier''ın 1963''te öne sürdüğü karşı örnekler bu tanımı köklü biçimde sarsmıştır.\n\nRasyonalizm, saf aklın duyu deneyiminden bağımsız olarak güvenilir bilgi üretebileceğini savunur. Descartes''ın "Cogito ergo sum" (Düşünüyorum, öyleyse varım) özdeyişi bu yaklaşımın simgesidir. Empirizm ise tüm bilginin nihayetinde duyusal deneyimden kaynaklandığını öne sürer; Locke, Berkeley ve Hume bu geleneğin baş temsilcileridir. Kant ise "Saf Aklın Eleştirisi" adlı yapıtında her iki geleneği sentezleyerek a priori bilginin zihindeki kategoriler ve formlara dayandığını göstermiştir.\n\nÇağdaş epistemoloji sosyal boyutu giderek daha fazla önemsemektedir. Feminist epistemoloji bilginin nesnel değil, perspektife bağlı olduğunu ve egemen bakış açısının kimin deneyiminin "evrensel" sayılacağını belirlediğini öne sürer. Sanal epistomik topluluklarda bilginin nasıl üretildiği ve dolaşıma girdiği ise dijital çağın yeni araştırma gündemleri arasına girmiştir.',
  ARRAY['epistemoloji','felsefe','bilgi','ALES'], 'published'),

  (gen_random_uuid(), 'Psikolojide Bilişsel Süreçler', 'Psikoloji', 'ALES', 4, 340, 4,
E'Bilişsel psikoloji, insanın bilgiyi nasıl algıladığını, işlediğini, depoladığını ve kullandığını inceler. 1950''lerde davranışçılığa yönelik tepki olarak doğan bu yaklaşım, zihin süreçlerini bilgisayar metaforu çerçevesinde kavramsallaştırmıştır.\n\nDikkat, duyusal uyaranlar arasından belirli olanları seçip işleyen zihinsel kaynakların dağılımıdır. Filtre teorileri (Broadbent, Treisman) farklı aşamalarda gerçekleşen bu filtreleme süreçlerini açıklamaktadır. Çalışma belleği ise anlık bilgiyi geçici olarak tutan ve işleme tabi kılan kapasitesi sınırlı bir sistemdir; Baddeley''ın modelinde merkezi yönetici, sesli döngü ve uzamsal-görsel taslak gibi alt bileşenler tanımlanmıştır.\n\nBilişsel yanlılıklar, insanın bilgiyi işleme ve karar verme süreçlerinde sergilediği sistematik hata örüntüleridir. Daniel Kahneman''ın Sistem 1 (hızlı, otomatik, sezgisel) ve Sistem 2 (yavaş, çabalı, analitik) ayrımı bu yanlılıkların çoğunu açıklamaktadır. Doğrulama yanlılığı, çapalama etkisi ve mevcutluk sezgisi en yaygın bilişsel yanlılıklar arasında sayılmaktadır.',
  ARRAY['psikoloji','biliş','karar','ALES'], 'published'),

  (gen_random_uuid(), 'Küresel İklim Değişikliği', 'Çevre Bilimleri', 'ALES', 3, 325, 4,
E'Yirminci yüzyılın ortasından bu yana fosil yakıt yakılması, ormansızlaşma ve sanayi emisyonları atmosferdeki sera gazı konsantrasyonlarını dramatik biçimde artırmıştır. Karbondioksit seviyesi sanayi öncesi 280 ppm değerinden 420 ppm''i aşan güncel değerine yükselmiştir. Bu değişim sera etkisini güçlendirerek küresel ortalama sıcaklıkta 1,1 °C''lik bir artışa neden olmuştur.\n\nİklim değişikliğinin somut etkileri polar bölgelerde özellikle belirgindir: Arktik deniz buzu rekor düşük seviyelere gerilemiş, buzul erimesi deniz seviyesinin yükselmesini hızlandırmaktadır. Aşırı hava olaylarının sıklığı ve şiddeti artmakta; seller, kuraklıklar ve tropik fırtınalar giderek daha yıkıcı boyutlar kazanmaktadır.\n\nParis Anlaşması (2015) küresel ısınmayı 2 °C ile sınırlandırma ve tercihen 1,5 °C''de tutma hedefini ortaya koymuştur. Yenilenebilir enerjiye geçiş, enerji verimliliği, sürdürülebilir tarım ve karbon tutma teknolojileri bu hedefe ulaşmak için kritik araçlar olarak öne çıkmaktadır. Bununla birlikte mevcut politika taahhütleri bu hedeflerden hâlâ uzak kalmaktadır.',
  ARRAY['iklim','çevre','sürdürülebilirlik','ALES'], 'published'),

  (gen_random_uuid(), 'Nörobilim ve Bilinç', 'Nörobilim', 'ALES', 5, 350, 4,
E'Bilinç, nörobilimin en çetin sorularından birini oluşturmaktadır: Beynin nöral aktivitesi öznel deneyimi —sıcaklık hissi, renklerin algılanması ya da acı— nasıl üretmektedir? Filozoflar ve bilim insanları bu "zor problem"i açıklamak için yüzyıllardır mücadele etmektedir.\n\nGlobal alan teorisi (Dehaene ve Changeux) bilincin geniş kortikal ağlar arasındaki bilgi yayılımıyla ortaya çıktığını öne sürer. Entegre bilgi teorisi (Tononi) ise bilinci, bir sistemin entegre bilgi üretme kapasitesinin (phi değeri) bir işlevi olarak matematiksel biçimde tanımlamaya çalışır. Her iki yaklaşım da bilinçli ve bilinçsiz zihinsel süreçler arasındaki sınırı nöral ölçütlerle çizmeye çalışmaktadır.\n\nUyku, anestezi ve vejetatif durum çalışmaları bilinç mekanizmalarını tersine mühendislik yöntemiyle anlamlandırmada değerli veriler sunmaktadır. Nöroimgeleme teknolojilerindeki (fMRI, EEG) gelişmeler kilitlenme sendromlu hastalar gibi davranışsal yanıt veremeyen bireylerde bilincin varlığını saptamamızı sağlamıştır. Yapay zeka sistemlerinin bilinç sahibi olup olamayacağı ise tartışmalar açısından çok daha derin felsefi katmanlar içermektedir.',
  ARRAY['nörobilim','bilinç','beyin','ALES'], 'published'),

  (gen_random_uuid(), 'İstatistiksel Analizde Temel Kavramlar', 'İstatistik', 'ALES', 4, 330, 4,
E'İstatistik, verilerin toplanması, düzenlenmesi, analizi ve yorumlanmasıyla ilgilenen bilim dalıdır. Betimleyici istatistik verileri özetlemeye yarayan ölçütleri (ortalama, ortanca, standart sapma gibi) kapsamaktadır. Çıkarımsal istatistik ise örneklem verilerinden ana kitleye ilişkin çıkarımlar yapmayı ve olasılık çerçevesinde hipotezleri sınamayı amaçlar.\n\nNormal dağılım (Gauss eğrisi) istatistiğin temel kavramlarından birini oluşturmaktadır. Pek çok doğal ve sosyal olgu normal dağılıma yakın bir yapı sergilediğinden bu dağılım özel bir öneme sahiptir. Z-skoru, bir değerin ortalamanın kaç standart sapma uzaklığında olduğunu verir ve dağılımlar arası karşılaştırmalara olanak tanır.\n\nHipotez testlerinde Type I hatası (gerçekte doğru olan sıfır hipotezini reddetmek) ve Type II hatası (gerçekte yanlış olan sıfır hipotezini kabul etmek) arasında bir denge kurulmak zorundadır. P değeri, verilen verinin sıfır hipotezi doğruyken gözlemlenmesi olasılığını ifade eder; 0,05 eşiği bilimsel çevrelerde yaygın kabul görmekle birlikte eleştirilmektedir. Büyük veri çağında istatistiksel anlamda anlamlı olanı pratik açıdan önemli olandan ayırt etmek giderek daha kritik bir beceri hâline gelmektedir.',
  ARRAY['istatistik','analiz','veri','ALES'], 'published');

