INSERT INTO text_library (id, title, category, exam_type, difficulty, word_count, estimated_read_time, body, tags, status)
VALUES
  (gen_random_uuid(), 'Atatürk''ün Eğitim Reformları', 'Türk İnkılabı', 'KPSS', 2, 285, 3,
E'Mustafa Kemal Atatürk''ün önderliğinde gerçekleştirilen eğitim reformları, yeni kurulan Türkiye Cumhuriyeti''nin temellerini şekillendirmiştir. 1924''te Tevhid-i Tedrisat (Öğretim Birleştirme) Kanunu''nun çıkarılmasıyla tüm okullar Millî Eğitim Bakanlığı çatısı altında toplandı ve medreseler kapatıldı.\n\n1928''deki harf devrimi belki de en köklü kültürel dönüşümü simgelemektedir. Arap alfabesinin yerini Latin kökenli Türk alfabesi aldı. Ardından başlatılan millet mektepleri kampanyasıyla kısa sürede milyonlarca vatandaşa yeni alfabeyle okuma yazma öğretildi. Bu kampanyanın lideri Atatürk''ün bizzat köy köy dolaşarak ders vermesi tarihsel bir simge hâline gelmiştir.\n\n1933''te gerçekleştirilen üniversite reformuyla İstanbul Darülfünunu modernleştirilerek İstanbul Üniversitesi kuruldu. Nazizm''den kaçan Avrupalı akademisyenler Türkiye''ye davet edilerek yeni kurulan üniversitelere bilimsel katkı sağlamak üzere göreve çağrıldı. Köy Enstitüleri ise 1940''larda hayata geçirilen özgün bir eğitim modeliyle kırsal kesimde yetişmiş öğrencileri öğretmen ve kalkınma ajanı olarak yetiştirmeyi hedefledi.',
  ARRAY['Atatürk','eğitim','reform','KPSS'], 'published'),

  (gen_random_uuid(), 'Türkiye''nin Anayasal Düzeni', 'Hukuk', 'KPSS', 3, 300, 3,
E'Türkiye''nin yürürlükteki Anayasası 1982 yılında kabul edilmiş, o tarihten bu yana pek çok önemli değişikliğe uğramıştır. Temel hak ve özgürlükleri güvence altına alan, devletin temel yapısını ve kuvvetler ayrılığı ilkesini belirleyen bu belge modern hukuk devletinin temelini oluşturmaktadır.\n\nAnayasanın değiştirilemez maddeleri cumhuriyetin niteliklerini tanımlamaktadır: Türkiye, demokratik, laik ve sosyal bir hukuk devletidir. Yasama yetkisi Türkiye Büyük Millet Meclisi''ne ait olup tek meclisli bir yapı benimsenmiştir. 2017 anayasa değişiklikleriyle cumhurbaşkanlığı hükûmet sistemine geçilmiş ve yürütme yetkisi cumhurbaşkanlığında toplanmıştır.\n\nAnayasa Mahkemesi, yasaların anayasaya uygunluğunu denetlemekle görevlidir. Bireysel başvuru hakkı 2010''dan bu yana vatandaşlara, temel haklarının ihlal edildiğini düşündüklerinde doğrudan Anayasa Mahkemesi''ne gitme imkânı tanımaktadır. Türkiye, Avrupa İnsan Hakları Mahkemesi''nin yargı yetkisini de tanımış olup bu mahkemenin kararları iç hukuku etkilemektedir.',
  ARRAY['anayasa','hukuk','Türkiye','KPSS'], 'published'),

  (gen_random_uuid(), 'Millî Mücadele Dönemi ve Kurtuluş Savaşı', 'Tarih', 'KPSS', 2, 310, 3,
E'Birinci Dünya Savaşı''nın ardından imzalanan Mondros Mütarekesi (30 Ekim 1918) Osmanlı Devleti''ni İtilaf güçlerinin işgaline açık bıraktı. İzmir''in 15 Mayıs 1919''da Yunan kuvvetlerince işgal edilmesi ise Türk halkında derin bir direniş bilinci uyandırdı.\n\nMustafa Kemal Atatürk, 19 Mayıs 1919''da Samsun''a çıkışıyla Millî Mücadele''yi fiilen başlattı. Erzurum ve Sivas kongrelerinde alınan kararlar millî irade ve tam bağımsızlık ilkelerini temel direnek olarak belirledi. 23 Nisan 1920''de Ankara''da TBMM''nin açılmasıyla yeni Türk devletinin temelleri atılmış oldu.\n\nBatı Cephesi''nde yaşanan İnönü muharebeleri kritik zaferler kazandırdı. 26 Ağustos 1922''de başlayan Büyük Taarruz Yunan kuvvetlerini Anadolu''dan sürdü ve 9 Eylül''de İzmir''in kurtuluşuyla noktalandı. Lozan Antlaşması (24 Temmuz 1923) bu savaşı diplomatik açıdan resmileştirerek Türkiye Cumhuriyeti''nin sınırlarını uluslararası alanda tanıttı. 29 Ekim 1923''te ise cumhuriyet ilan edildi.',
  ARRAY['kurtuluş savaşı','tarih','Atatürk','KPSS'], 'published'),

  (gen_random_uuid(), 'Osmanlı Millet Sistemi', 'Tarih', 'KPSS', 3, 290, 3,
E'Osmanlı millet sistemi, imparatorluk bünyesindeki farklı etnik ve dinî toplulukların kendi iç işlerini yönetmelerine olanak tanıyan özgün bir idari düzenlemedir. Bu sistem altında Müslümanlar, Ortodoks Hristiyanlar, Ermeni Hristiyanlar ve Yahudiler ayrı topluluklar (milletler) biçiminde örgütlendi.\n\nHer millet kendi dini liderliği aracılığıyla kişisel statü hukuku, eğitim ve sosyal hizmetler alanlarında öz yönetim hakkına sahipti. Ermeni patrikhanesi, Rum Ortodoks ekümenik patrikhanesi ve Yahudi hahambaşılığı bu özerk yapıların kurumsal ifadeleriydi. Padişah ise çeşitli toplulukların haklarını güvence altına alan en yüksek otorite konumundaydı.\n\nMillet sistemi uzun süre belirli düzeyde bir toplumlar arası huzurun sürdürülmesini sağladı. Ancak 19. yüzyılda Batılı milliyetçilik akımlarının yayılması ve ekonomik çıkarlar bu dengeyi sarstı. Ayrılıkçı hareketlerin güçlenmesiyle birlikte imparatorluk çok cepheli toplumsal gerilimlerle yüzleşmek zorunda kaldı. Millet sisteminin mirası bugün de Balkanlar ve Orta Doğu''daki azınlık hakları tartışmalarında yankısını bulmaktadır.',
  ARRAY['osmanlı','millet sistemi','tarih','KPSS'], 'published'),

  (gen_random_uuid(), 'Türkiye''nin Ekonomik Kalkınma Süreci', 'Ekonomi', 'KPSS', 3, 300, 3,
E'Cumhuriyet''in ilk yıllarında Türkiye sanayisi son derece sınırlı bir düzeydeydi. Devletçilik ilkesi doğrultusunda kurulan devlet iktisadi teşekkülleri (KİT''ler) temel sanayi kollarını ve altyapı yatırımlarını kamu eliyle gerçekleştirdi. Sümerbank tekstil, Etibank madencilik ve KBI''ler demir-çelik üretiminde öncü kuruluşlar oldu.\n\n1980''lerde gerçekleştirilen ekonomik liberalizasyon programı kamu müdahalesini azaltarak dışa açık bir piyasa ekonomisine geçiş sürecini başlattı. İhracata yönelik büyüme modeli, Türkiye''nin 1990''lı yıllar boyunca ortalama yüzde beş civarında büyümesine katkıda bulundu. Aynı dönemde yüksek enflasyon, kamu açıkları ve döviz krizleri ekonomik istikrarın önündeki ciddi engeller olarak öne çıktı.\n\n2001 krizi ardından hayata geçirilen güçlü ekonomi programı bankacılık sektörünü köklü biçimde yeniden yapılandırdı ve enflasyonu tek haneli rakamların altına indirdi. 2000''li yıllarda yabancı yatırım girişleri hız kazanırken sanayi çıktısı ve ihracatta belirgin artışlar yaşandı. Orta-yüksek gelir grubuna giren Türkiye, gelişmiş ülkelerle gelir açığını kapatma konusunda ilerleme kaydetmekle birlikte verimliliği artırma ve ihracat ürün çeşitliliğini genişletme alanlarında önemli yapısal sorunlarla boğuşmaya devam etmektedir.',
  ARRAY['ekonomi','kalkınma','Türkiye','KPSS'], 'published'),

  (gen_random_uuid(), 'Türkiye''de Demokratikleşme Süreci', 'Siyasi Tarih', 'KPSS', 3, 285, 3,
E'Türkiye''de çok partili siyasi hayat 1946''da fiilen başlamış ve 1950 seçimlerinin ardından iktidarda el değişiminin yaşanmasıyla pekişmiştir. Adnan Menderes liderliğindeki Demokrat Parti''nin iktidara gelişi Türk demokrasisinin köklü bir dönüşümünü simgelemiştir.\n\nTürkiye''nin demokratikleşme süreci kesintisiz bir çizgi izlememiş; 1960, 1971 ve 1980''de askeri müdahalelerle sekteye uğramıştır. Her müdahalenin ardından sivil yönetime dönüş sağlanmış, ancak siyasi kültür ve kurumsal yapı üzerindeki kalıcı izler derin biçimde hissedilmiştir. 1982 Anayasası askeri yönetim döneminde hazırlanmış ve temel hakları kısıtlayan düzenlemeler içermiştir.\n\nAvrupa Birliği üyelik sürecinde yürütülen reformlar yargı bağımsızlığı, azınlık hakları ve sivil denetim alanlarında önemli değişiklikler getirmiştir. 2000''li yılların başında demokratikleşme adına atılan bu adımlar insan hakları örgütlerince olumlu karşılanmıştır. Bununla birlikte basın özgürlüğü, yargı bağımsızlığı ve muhalefete yönelik kısıtlamalar gibi konularda endişeler varlığını sürdürmektedir.',
  ARRAY['demokrasi','siyaset','tarih','KPSS'], 'published'),

  (gen_random_uuid(), 'Türkiye''nin Dış Politikası', 'Dış Politika', 'KPSS', 3, 280, 3,
E'Türkiye''nin dış politikası, jeopolitik konumunun şekillendirdiği özgün bir denklem içinde Batı ittifakları, bölgesel güçler ve yükselen küresel aktörler arasında hassas bir denge kurma çabasını yansıtmaktadır. NATO''nun kurucusu ve uzun süreli üyesi olan Türkiye, Batı savunma mimarisinin kilit bir unsurunu oluşturmaktadır.\n\nTürkiye-AB ilişkileri 1999''da adaylık statüsünün tanınmasıyla yeni bir boyut kazanmış; ancak sonraki dönemde müzakereler askıya alınmış ve ilişkiler gerilemiştir. Öte yandan Türkiye bölgesel liderlik rolüne soyunarak Kafkasya, Orta Doğu ve Balkanlar''da etkin bir politika izlemektedir. "Sıfır sorun" olarak kavramsallaştırılan komşularla ilişkileri normalleştirme politikası başlangıçta umut verici sonuçlar doğurmuş; ancak Arap Baharı sonrası gelişmeler bu politikanın sınırlarını açığa çıkarmıştır.\n\nRusya ile ilişkiler özellikle enerji bağımlılığı (TürkAkım boru hattı), savunma alımları (S-400) ve Suriye politikasındaki farklılıklar nedeniyle karmaşık bir yapı sergilemektedir. Türkiye''nin çok boyutlu dış politikası zaman zaman müttefikleriyle gerilimlere yol açmakta, bununla birlikte Ankara''nın bölgesel arabuluculuk kapasitesini de pekiştirmektedir.',
  ARRAY['dış politika','Türkiye','jeopolitik','KPSS'], 'published'),

  (gen_random_uuid(), 'Anadolu''nun Coğrafi Özellikleri', 'Coğrafya', 'KPSS', 2, 270, 3,
E'Anadolu Yarımadası üç tarafı denizlerle çevrili bir coğrafi bütündür: batıda Ege Denizi, kuzeyde Karadeniz ve güneyde Akdeniz. Bu yarımada yaklaşık 755.000 km² yüzölçümüyle dağlık ve plato niteliği ağır basan bir coğrafyaya sahiptir.\n\nAnadolu''nun iç bölgelerini Orta Anadolu Platosu kaplar; ortalama yüksekliği 1.000-1.200 metre arasında değişen bu platoda karasal iklim egemendir. Kuzey ve güney kıyıları boyunca uzanan dağ sıraları —Karadeniz Dağları ile Toroslar— iç bölgelere iklimsel etkilerin nüfuzunu önler ve kıyılar ile iç kesimler arasında belirgin bir iklim kuşaklanması yaratır.\n\nAnadolu''nun su kaynakları tarih boyunca stratejik önem taşımıştır. Fırat, Dicle, Kızılırmak ve Yeşilırmak başlıca akarsular arasındadır. Güneydoğu Anadolu Projesi (GAP), Fırat ve Dicle üzerinde inşa edilen barajlar ve sulama sistemleriyle bölgenin ekonomik potansiyelini harekete geçirmeyi amaçlayan kapsamlı bir kalkınma programıdır.',
  ARRAY['coğrafya','Anadolu','Türkiye','KPSS'], 'published'),

  (gen_random_uuid(), 'İnsan Hakları ve Türkiye', 'Hukuk', 'KPSS', 3, 280, 3,
E'İnsan hakları, salt ülkeden ülkeye değişen yasal düzenlemelere değil; bireyin yalnızca insan olması nedeniyle sahip olduğu evrensel haklara dayanır. 1948 BM İnsan Hakları Evrensel Beyannamesi bu anlayışın kurucu belgesidir ve onu imzalayan devletler temel standartları korumayı taahhüt etmiştir.\n\nTürkiye, Avrupa İnsan Hakları Sözleşmesi''ni onaylamış ve Avrupa İnsan Hakları Mahkemesi''nin yargı yetkisini kabul etmiştir. Bu mekanizma bireylerin hak ihlali iddiasıyla devleti uluslararası bir mahkeme önüne çıkarabilmesine olanak tanır. Türkiye''nin Strasbourg''dan aldığı mahkûmiyet kararları çoğunlukla ifade özgürlüğü, gözaltı süreleri ve adil yargılanma hakkı ile ilgili olmuştur.\n\n1982 Anayasası''nda 2001 ve sonraki yıllarda yapılan değişiklikler temel hak ve özgürlüklerin kapsamını genişletmeyi amaçlamıştır. İşkence yasağı mutlak hâle getirilmiş, tutukluluk süreleri kısaltılmış ve bazı hakların kullanımındaki kısıtlamalar yumuşatılmıştır. Sivil toplum kuruluşları ve basın özgürlüğü alanında kaydedilen gelişmeler ile süregelen sorunlar gündemin odağında kalmaya devam etmektedir.',
  ARRAY['insan hakları','hukuk','Türkiye','KPSS'], 'published'),

  (gen_random_uuid(), 'İkinci Dünya Savaşı ve Türkiye', 'Tarih', 'KPSS', 3, 285, 3,
E'Türkiye İkinci Dünya Savaşı''na fiilen katılmamış; ancak ülke bu süre zarfında ağır diplomatik baskılarla karşı karşıya kalmıştır. Alman kuvvetlerinin 1941''de Balkanlar''ı işgal etmesi Türkiye''nin yakın çevresini doğrudan tehdit altına almıştır.\n\nTürkiye''nin tarafsızlığını koruma stratejisi hem Mihver hem de İtilaf devletleriyle hassas ikili ilişkilerin dengelenmesini gerektirmiştir. Ülke Almanya ile 1941''de bir saldırmazlık paktı imzalamış; öte yandan İngiltere ve ABD ile ekonomik ve diplomatik bağlarını koparmamıştır. Almanya''ya krom ihracatının sürdürülmesi önemli bir tartışma konusu olmuş ve zamanla kısıtlamalar getirilmiştir.\n\nTürkiye''nin savaşın son aşamasında Almanya''ya savaş ilan etmesi (Şubat 1945) Birleşmiş Milletler''in kurucu üyeleri arasında yer almak için stratejik bir zorunluluktu. Savaşın Türkiye üzerindeki ekonomik etkileri ağır olmuştur: Varlık Vergisi (1942) azınlık tüccarları orantısız biçimde etkileyerek toplumsal gerginliklere yol açmıştır. Savaş sonrasında Türkiye NATO üyeliğine doğru yönelerek siyasi duruşunu Batı Bloğu yanında net biçimde belirlemiştir.',
  ARRAY['tarih','ikinci dünya savaşı','Türkiye','KPSS'], 'published');

