INSERT INTO text_library (id, title, category, exam_type, difficulty, word_count, estimated_read_time, body, tags, status)
VALUES
  (gen_random_uuid(), 'Uzay Keşfinin Geleceği', 'Teknoloji', 'General', 2, 300, 3,
E'İnsanlığın uzayı keşfetme itkisi Sputnik''in fırlatılmasından (1957) bu yana hız kazanarak sürmektedir. Bugün artık devlet ajanslarının yanı sıra SpaceX, Blue Origin ve diğer özel şirketler uzay yarışına ortak olmuş ve maliyetleri dramatik biçimde düşürerek erişimi demokratikleştirmektedir.\n\nAy''a geri dönüş planları gündemin üst sıralarına yerleşmiştir. NASA''nın Artemis programı 2020''li yıllarda insanlı Ay görevlerini hedeflemekte olup bu sefer amacın kalıcı bir üs kurmak olduğu vurgulanmaktadır. Mars ise uzun vadeli hedefler arasında birinci sıraya oturmuştur; astronot sağlığı üzerindeki uzun süreli uzay yolculuğu etkileri bu misyonun önündeki en büyük engeldir.\n\nUzay araştırmacıları uydular, teleskoplar ve uzay istasyonları aracılığıyla Güneş Sistemi''ni ve ötesini haritalandırmaya devam etmektedir. James Webb Uzay Teleskobu daha önce hiç bu kadar ayrıntıyla görüntülenemeyen erken evren galaksilerini ve öte gezegen atmosferlerini gözler önüne sermektedir. Uzay keşfi yalnızca bilimsel bilgiyi genişletmemekte; aynı zamanda Dünya''da günlük hayatı köklü biçimde dönüştüren sayısız teknolojik yan ürün üretmektedir.',
  ARRAY['uzay','teknoloji','bilim','General'], 'published'),

  (gen_random_uuid(), 'Meditasyonun Beyne Etkisi', 'Sağlık', 'General', 2, 285, 3,
E'Meditasyon binlerce yıllık geçmişe sahip bir zihinsel pratik olmasına karşın bilimsel araştırmacılar bu alana yalnızca son otuz yılda ilgi duymaya başlamıştır. Dikkat ve öz-farkındalığı geliştirmeye odaklanan bu pratiğin beyin üzerindeki etkileri artık nöroimgeleme teknolojileriyle ölçülebilmektedir.\n\nDüzenli meditasyon pratiğinin amigdalayı (korku ve kaygı işleyen beyin bölgesi) küçülttüğünü, öte yandan prefrontal korteks hacmini artırdığını gösteren çalışmalar dikkat çekmektedir. Bu bölge karar alma ve duygusal düzenlemeyle ilişkilidir. Farkındalık meditasyonu stresin biyolojik göstergesi olan kortizol düzeylerini düşürmekte ve bağışıklık sistemini olumlu yönde etkilemektedir.\n\nFarkındalığa dayalı bilişsel terapi (MBCT) tekrarlayan depresyon vakalarında etkili bir tedavi yöntemi olarak kabul görmüş ve klinik kılavuzlara girmiştir. Bununla birlikte meditasyonun tüm etkileri henüz netlik kazanmamış olup plasebo kontrolünü sağlamak metodolojik açıdan güçtür. Öte yandan araştırma bulguları yalnızca birkaç haftalık düzenli pratiğin bile ölçülebilir faydalar yarattığına işaret etmektedir.',
  ARRAY['meditasyon','sağlık','beyin','General'], 'published'),

  (gen_random_uuid(), 'Türk Mutfağının Zengin Tarihi', 'Kültür', 'General', 1, 265, 2,
E'Türk mutfağı, Orta Asya''nın göçebe geleneklerini Anadolu''nun bereketli tarım kültürü ve Osmanlı saray mutfağının inceliğiyle harmanlamıştır. Coğrafi ve kültürel bu çeşitlilik, bölgeden bölgeye köklü biçimde değişen lezzet ve malzeme zenginliğini doğurmuştur.\n\nEkmek Türk mutfağının merkezinde yer alır: köy ekmekleri, lavaş, pide ve simit Türk sofralarının vazgeçilmez unsurlarıdır. Kebap kültürü yüzyıllarca yayılan coğrafyaların birikimini taşır; Adana''nın acılı kıyma kebabından Bursa''nın efsanevi İskender''ine uzanan bu geniş yelpaze Türk mutfağının çeşitliliğini yansıtır. Balık Ege ve Karadeniz kıyılarında sofraların baş tacı olurken İç Anadolu''da et ve buğday ağırlıklı yemekler ön plana çıkar.\n\nTatlılar da o denli çeşitlidir. Baklava, künefe, kazandibi ve aşure farklı teknikleri ve tatları yansıtır. Türk kahvesi ve çayın kültürel önemi yalnızca bir içecek boyutunu çok aşmakta; toplumsal ilişkilerin, sohbetin ve misafirperverliğin simgeleri olarak anlam kazanmaktadır. Türk mutfağı 2010''da UNESCO tarafından Somut Olmayan Kültürel Miras listesine alınan Türk kahvesi kültürüyle uluslararası alanda tanınırlık kazanmaya devam etmektedir.',
  ARRAY['yemek','kültür','tarih','General'], 'published'),

  (gen_random_uuid(), 'Dijital Çağda Mahremiyet', 'Teknoloji', 'General', 2, 290, 3,
E'İnternetin günlük hayatımıza girmesiyle birlikte kişisel verilerin toplanması, depolanması ve analiz edilmesi olağanüstü boyutlara ulaşmıştır. Her arama sorgusu, alışveriş tercihi ve sosyal medya etkileşimi şirketler ve hükümetler tarafından derlenen dijital bir iz bırakmaktadır.\n\nVeri gizliliği endişeleri yalnızca kişisel bilgilerin ifşa edilmesiyle sınırlı kalmamaktadır. Kişisel verilere dayalı profilleme, reklam hedeflemesi ve siyasi mesaj kişiselleştirmesinin bireyin özerkliğini nasıl etkilediği sorusu tartışmaların odağına taşınmıştır. Cambridge Analytica skandalı ve benzeri vakalar büyük veri manipülasyonunun toplumsal sonuçlarını gözler önüne sermiştir.\n\nAvrupa Birliği''nin Genel Veri Koruma Yönetmeliği (GDPR), bireylere kişisel verileri üzerinde daha güçlü haklar tanıyan kapsamlı bir düzenleyici çerçeve sunmaktadır. Erişim hakkı, silinme hakkı ve veri taşınabilirliği bu haklar arasında sayılabilir. Türkiye de 6698 sayılı Kişisel Verilerin Korunması Kanunu ile bu alanda benzer güvenceler getirmiştir.',
  ARRAY['mahremiyet','teknoloji','veri','General'], 'published'),

  (gen_random_uuid(), 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?', 'Teknoloji', 'General', 2, 300, 3,
E'Yapay zeka artık bilim kurgu filmlerinin değil, gündelik hayatın ayrılmaz bir parçasıdır. Akıllı telefon asistanlarından müzik öneri algoritmalarına, e-posta spam filtrelerinden yüz tanıma sistemlerine kadar YZ pek çok uygulama tarafından sessizce çalıştırılmaktadır.\n\nSağlık alanında YZ, radyoloji görüntülerini tarayarak doktorların gözden kaçırabileceği ince patolojileri tespit edebilmektedir. İlaç keşfini hızlandırmak ve kişiselleştirilmiş tedavi protokolleri geliştirmek için büyük veri setlerini analiz etmektedir. Eğitimde ise uyarlanabilir öğrenme platformları her öğrencinin hızına ve anlayış seviyesine göre içerik ve geri bildirim kişiselleştirmektedir.\n\nÖte yandan YZ tabanlı otomasyon işgücü piyasasını yeniden biçimlendirmektedir. Rutin ve yinelemeli görevler hızla otomasyona geçerken yaratıcılık, eleştirel düşünme ve duygusal zeka içeren meslekler daha dirençli bir görünüm sergilemektedir. Gelecek işgücünün YZ ile iş birliği yapma becerisini edinmesi öncelikli bir eğitim hedefi hâline gelmektedir.',
  ARRAY['yapay zeka','teknoloji','gelecek','General'], 'published'),

  (gen_random_uuid(), 'Okyanusların Gizemli Derinlikleri', 'Doğa', 'General', 2, 280, 3,
E'Dünya''nın yüzeyinin yüzde yetmişinden fazlasını kaplayan okyanuslar, gezegenimizin en az keşfedilmiş bölgelerini barındırmaktadır. Okyanus tabanının yüzde sekseninden fazlası hâlâ haritalandırılmamış durumdadır; bu oran Ay''ın yüzeyindeki haritalandırılmamış alandan bile yüksektir.\n\nDerin okyanus ekosistemleri, ışık ve sıcaklığın aşırı yetersizliğine karşın olağanüstü biyoçeşitlilik barındırmaktadır. Hidrotermik bacalar (siyah ışıltılar) güneş enerjisi yerine kimyasal enerjiyi (kemotrofik) kullanan canlıların yaşadığı benzersiz habitatlardır. Bu ekosistemlerin keşfi yaşamın oksijenin ve fotosentezin bulunmadığı ortamlarda da var olabileceğini kanıtlaması açısından tarihsel bir öneme sahiptir.\n\nOkyanuslar küresel iklim sisteminin düzenlenmesinde kritik bir rol oynamaktadır. Büyük miktarlarda karbondioksit emen ve ısıyı depolayan okyanuslar, atmosferdeki iklim etkilerini uzun süre boyunca dengeleme işlevi görmüştür. Okyanus asitliğindeki artış, ısınma ve kirlilik ise bu ekosistemlerin sağlığını ciddi biçimde tehdit etmektedir.',
  ARRAY['okyanus','doğa','bilim','General'], 'published'),

  (gen_random_uuid(), 'Müziğin Psikolojik Etkileri', 'Kültür', 'General', 2, 275, 3,
E'Müzik, insan beynini diğer hiçbir sanat türünden farklı biçimlerde etkileyen güçlü bir olgudur. Müzik dinlemek; ödül, duygu, hafıza ve hareketle ilişkili birden fazla beyin bölgesini eş zamanlı olarak aktive etmektedir. Bir şarkının dinleyende goosebumps (tüyler ürpermesi) yaratması, beynin dopamin salgılaması ve zevk merkezlerinin ateşlenmesiyle ilişkilidir.\n\nMüziğin terapi aracı olarak kullanımı onlarca yıldır araştırılmaktadır. Müzik terapi ağrıyı azaltmakta, kaygıyı yatıştırmakta ve Alzheimer hastalarında uzun süreli anıların yüzeye çıkmasına yardımcı olmaktadır. Bu son olgu son derece dikkat çekicidir: Hastalık nedeniyle pek çok anısını yitirmiş bireyler gençliklerinde sevdikleri şarkıları çoğu kez kolaylıkla hatırlayabilmektedir.\n\nMüziğin öğrenmeye etkisi de kapsamlı biçimde çalışılmıştır. "Mozart Etkisi" hipotezi aşırı genelleştirilmiş olmakla birlikte müzik eğitiminin çocuklarda dil becerilerini, matematiksel düşünceyi ve yürütücü işlevleri geliştirdiğine dair güçlü kanıtlar mevcuttur. Ritim ve melodi hafıza ile dili desteklemekte; bu yüzden bazı eğitimciler içerikleri ezber yoluyla öğretmeyi tercih etmektedir.',
  ARRAY['müzik','psikoloji','sağlık','General'], 'published'),

  (gen_random_uuid(), 'Yeşil Enerji ve Sürdürülebilir Gelecek', 'Çevre', 'General', 2, 290, 3,
E'Fosil yakıtlara olan küresel bağımlılığı azaltmak hem çevre hem de ekonomik açıdan zorunlu bir hedef hâline gelmiştir. Güneş ve rüzgar enerjisi teknolojileri son on yılda dramatik maliyet düşüşleri yaşayarak birçok bölgede kömür ve gaz santrallerine kıyasla daha ekonomik seçenekler hâline gelmiştir.\n\nGüneş paneli verimliliği yıllar içinde sürekli iyileşmiş, üretim maliyeti ise çarpıcı biçimde gerilemiştir. Açık deniz rüzgar çiftlikleri, karadan çok daha güçlü ve sürekli rüzgar kaynaklarına erişim sağlayarak enerji üretimini önemli ölçüde artırmaktadır. Hidrojen ekonomisi, yenilenebilir enerjinin depolanabileceği ve taşıtlar ile sanayi için yakıt olarak kullanılabileceği temiz bir gelecek vaat etmektedir.\n\nYenilenebilir enerjiye geçişin önündeki temel engeller üretilen enerjinin depolanması ve ızgara entegrasyonu sorunlarıdır. Batarya depolama teknolojilerindeki gelişmeler bu soruna çözüm yolları sunmakta; "akıllı enerji ızgaraları" hem arz hem talebi daha verimli dengelemeye olanak tanımaktadır. Türkiye yenilenebilir enerji kapasitesini artırmakta ve bu alanda hem güneş hem de rüzgar enerjisi kurulu gücünde kayda değer ilerleme kaydetmektedir.',
  ARRAY['enerji','çevre','sürdürülebilirlik','General'], 'published'),

  (gen_random_uuid(), 'Kuantum Fiziğinin Sırları', 'Bilim', 'General', 3, 295, 3,
E'Kuantum mekaniği, atom altı parçacıkların davranışını inceleyen ve klasik fiziğin sezgilerimizi alt üst eden çıkarımlarıyla şimdiye kadar formüle edilmiş en başarılı bilimsel teorilerden biridir. Dalga-parçacık ikiliği, bir elektronun hem dalga hem de parçacık özellikleri sergilediğini ortaya koyar; hangi özelliğin gözlemleneceğini ölçüm koşulları belirler.\n\nHeisenberg''in belirsizlik ilkesi bir parçacığın konumunun ve momentumunun aynı anda sonsuz hassasiyetle ölçülemeyeceğini söyler. Bu durum ölçüm cihazlarının yetersizliğinden değil, doğanın temel özelliğinden kaynaklanmaktadır. Kuantum dolanıklığı ise iki parçacığın aralarındaki mesafeden bağımsız olarak eş zamanlı şekilde birbirini etkileyebildiği gizemli bir olgudur; Einstein bu durumu "uzaktan ürkütücü etki" olarak nitelendirmiştir.\n\nKuantum bilgisayarlar klasik bilgisayarların üstesinden gelemeyeceği hesaplamaları gerçekleştirme potansiyeli taşımaktadır. Süperpozisyon ilkesini kullanan kuantum bitleri (qubit) aynı anda hem 0 hem de 1 değerini temsil edebildiğinden paralel işlem kapasitesi üstel biçimde artmaktadır. Bu teknoloji şifreleme, ilaç keşfi ve yapay zeka alanlarını kökten dönüştürebilecek potansiyel barındırmaktadır.',
  ARRAY['kuantum','fizik','bilim','General'], 'published'),

  (gen_random_uuid(), 'Dilin Evrimi ve Geleceği', 'Dilbilim', 'General', 3, 285, 3,
E'Dil, insanı diğer türlerden ayıran en temel özelliklerden biridir. Bugün dünyada konuşulan 7.000 civarındaki dilden yüzlercesi gelecek yüzyılda yok olma riskiyle karşı karşıyadır. Küreselleşme ve dijital iletişim egemen dillerin yayılımını hızlandırırken küçük toplulukların dillerini yaşatması giderek zorlaşmaktadır.\n\nDillerin tarihi seyri, karmaşık göç ve kültürel etkileşim süreçlerini yansıtır. Hintavrupa dil ailesi pek çok Avrupalı ve Asya dilini kapsamakta; binlerce yıl önce yaşamış ortak ata dili Proto-Hintavrupa, karşılaştırmalı dilbilim yöntemiyle yeniden kurgulanabilmektedir. Türk dilleri ise Orta Asya''dan Anadolu''ya uzanan geniş bir coğrafyaya yayılmış kendine özgü bir dil ailesi oluşturmaktadır.\n\nDijital çağ dilin kendisini de dönüştürmektedir. Emoji''ler, kısaltmalar ve internet jargonu yazı dilinde yeni ifade araçları yaratmaktadır. Yapay zeka çeviri araçları dil engellerini aşmayı kolaylaştırsa da kültürel nüansları ve bağlam odaklı anlamı tam olarak aktarmak hâlâ güçtür. Dil kayıplarının belgelenmesi ve miras dillerinin dijital araçlarla canlandırılması dilbilimcilerin ve toplulukların ortak gündemine girmiş bir sorumluluktur.',
  ARRAY['dil','dilbilim','kültür','General'], 'published');

